        $this->assertSame($arm1->toJson(), $back->toJson(), 'JSON string not stable for XdrAsset arm XdrAssetType_ASSET_TYPE_CREDIT_ALPHANUM4');
        $back2 = XdrAsset::fromJson($arm1->toJson());
